module.exports = function(RED) {
    "use strict";

    function NeuralDropoutNode(n) {
        RED.nodes.createNode(this, n);
        var node = this;
        node.rate = n.rate || 0.5;
        node.training = n.training !== false;
        node._held = null;

        node.neuralRelease = function() {
            if (node._held) {
                var h = node._held;
                node._held = null;
                h.msg.payload = h.output;
                h.send(h.msg);
                h.done();
            }
        };

        node.on("input", function(msg, send, done) {
            var input = msg.payload;
            if (!Array.isArray(input)) {
                input = [input];
            }

            var output;
            if (node.training) {
                var mask = input.map(function() { return Math.random() > node.rate ? 1 / (1 - node.rate) : 0; });
                output = input.map(function(v, i) { return v * mask[i]; });
                var dropped = mask.filter(function(v) { return v === 0; }).length;
                node.status({ fill: "yellow", shape: "ring", text: dropped + "/" + output.length + " dropped" });
            } else {
                output = input.slice();
                node.status({ fill: "green", shape: "dot", text: "inference (pass-through)" });
            }

            msg.neural = msg.neural || {};
            msg.neural.type = "dropout";
            msg.neural.shape = [output.length];
            msg.neural.rate = node.rate;
            msg.neural.step = (msg.neural.step || 0) + 1;

            if (msg.neural.hold && !node._held) {
                node._held = { output: output, msg: msg, send: send, done: done };
                node.status({ fill: "yellow", shape: "ring", text: "step " + msg.neural.step + " waiting..." });
                return;
            }

            msg.payload = output;

            if (RED.neural) { RED.neural.outputs[node.id] = { values: output, type: "neural-dropout", name: node.name || "", timestamp: Date.now(), shape: [output.length] }; }

            send(msg);
            done();
        });
    }

    RED.nodes.registerType("neural-dropout", NeuralDropoutNode);
};
